  "code": "def encode(message):
    """
    Encodes a message by converting vowels to their counterpart two letters ahead in the alphabet and swapping the case of all letters. It is assumed that the message contains only alphabetic characters.

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    vowels = {'a', 'e', 'i', 'o', 'u'}
    encoded_message = []

    for char in message:
        if char.lower() in vowels:
            # Convert vowel to its counterpart two letters ahead
            new_char = chr(ord(char) + 2)
        else:
            new_char = char

        # Swap the case of the character
        if new_char.isupper():
            new_char = new_char.lower()
        else:
            new_char = new_char.upper()

        encoded_message.append(new_char)

    return ''.join(encoded_message)",
